@@setlocal enabledelayedexpansion & @@findstr/v "^@@[fs].*&" "%~f0" | python.exe - & exit !errorlevel!/b&
import js7
import os
##!include agent_register_scriptinclude 
workflow_payload = {
    "TYPE": "Workflow",
    "version": "1.9.0",
    "timeZone": "Asia/Kolkata",
    "instructions": [
        {
            "TYPE": "Execute.Named",
            "jobName": "job1",
            "label": "job1_label"
        },
        {
            "TYPE": "Execute.Named",
            "jobName": "job2",
            "label": "job2_label"
        }
    ],
    "jobs": {
        "job1": {
            "agentName": "My Agent",
            "executable": {
                "TYPE": "ShellScriptExecutable",
                "script": "echo Hello JS7",

            }
        },
        "job2": {
            "agentName": "My Agent",
            "executable": {
                "TYPE": "ShellScriptExecutable",
                "script": "echo Goodbye JS7",

            }
        }
    }
}

workflow_path = os.environ.get("WORKFLOW_PATH")
controller_id = os.environ.get("JS7_CONTROLLER_ID", "controller")

# Store
response = client.inventory.manage.store_configuration(
    configuration=js7.model.Configuration(
        path=workflow_path,
        object_type=js7.model.DeployObjectType.WORKFLOW,
    ),
    payload=workflow_payload,
    no_invalid=True,
    audit_log=js7.model.AuditLog(comment="Workflow with labels"),
)
print("Stored:", response)

ok = client.inventory.deploy.configurations(
    controller_id=controller_id,
    deploy=[
        js7.model.DraftConfiguration(
            path=workflow_path,
            object_type=js7.model.DeployObjectType.WORKFLOW,
        )
    ]
)
print("Workflow deployed successfully", ok)
